import {
  DockItem,
  type DockItemData,
} from '@/components/azemmur/components/azemmur/floating-dock/dock-item';
import { DockRoot } from '@/components/azemmur/components/azemmur/floating-dock/dock-root';
import { DockSeparator } from '@/components/azemmur/components/azemmur/floating-dock/dock-separator';

type FloatingDockComponent = typeof DockRoot & {
  Item: typeof DockItem;
  Separator: typeof DockSeparator;
};

const FloatingDock = DockRoot as FloatingDockComponent;

FloatingDock.Item = DockItem;
FloatingDock.Separator = DockSeparator;

export { FloatingDock, type DockItemData };

